const alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789 .!?-_#()[]{}@/:;,';

/**
 * RSA Classic Simple
 * @param p 
 * @param q 
 * @param e 
 * @returns {encrypt: (message: string) => number[], decrypt: (encryptedMessage: number[]) => string, d: number}
  encrypt: (message: string) => number[] // Permet to encrypt the message
  decrypt: (encryptedMessage: number[]) => string // Permit to decrypt message
  d: number // private key
*/
function rsaClassicSimple(p, q, e) {
    const n = p * q;
    const phi = (p - 1) * (q - 1);
    const d = ExtendedEuclideAlgorithm(e, phi);

    return {
        encrypt: (message) => message.split("").map(letter => modPow(letterToNumber(letter), e, n)),
        decrypt: (encryptedMessage) => encryptedMessage.map(number => numberToLetter(modPow(number, d, n))).join(""),
        d
    }
}

/* 
 * Extended Euclide Algorithm
 * @param e the public key
 * @param phi the totient of n
 * @returns d which is the private key also equal to the inverse of e modulo phi
 */
function ExtendedEuclideAlgorithm(e, phi) {
    let [r, u, v, r1, u1, v1] = [phi, 1, 0, e, 0, 1];
    while (r1 !== 0) {
        const q = Math.floor(r / r1);
        [r, u, v, r1, u1, v1] = [r1, u1, v1, r - q * r1, u - q * u1, v - q * v1];
    }
    // v correspond à l'inverse modulaire de e modulo phi, mais peut être négatif.
    // On le ramène dans l'intervalle [0, phi-1] :
    return ((v % phi) + phi) % phi;
}

/**
 * (base ^ exponent) % modulus
 * @param base 
 * @param exponent 
 * @param modulus 
 * @returns (base ^ exponent) % modulus
 */
function modPow(base, exponent, modulus) {
    if (modulus === 1) return 0;
    let result = 1;
    base = base % modulus;
    while (exponent > 0) {
        if (exponent % 2 === 1) {
        result = (result * base) % modulus;
        }
        exponent = Math.floor(exponent / 2);
        base = (base * base) % modulus;
    }
    return result;
}

function letterToNumber(letter) {
    return alphabet.indexOf(letter);
}

function numberToLetter(number) {
    return alphabet.charAt(number);
}

const P = parseInt(readline());
const Q = parseInt(readline());
const E = parseInt(readline());
const type = readline();
const message = readline();

const rsa = rsaClassicSimple(P, Q, E);

if (type === "Encrypt") {
    console.log(rsa.encrypt(message).join("-"));
} else if (type === "Decrypt") {
    console.log(rsa.decrypt(message.split("-")))
}
console.log(rsa.d);
